from datetime import timedelta
from flask import Flask, session, request, redirect, url_for, render_template_string, flash

app = Flask(__name__)
app.secret_key = 'change-this-secret-key'
app.permanent_session_lifetime = timedelta(days=7)

USERS = {
    'admin': 'password',
    'user': 'password'
}

LOGIN_TEMPLATE = '''
<!doctype html>
<title>Login</title>
<h1>Login</h1>
{% with messages = get_flashed_messages() %}
  {% if messages %}
    <ul>
    {% for message in messages %}
      <li>{{ message }}</li>
    {% endfor %}
    </ul>
  {% endif %}
{% endwith %}
<form method="post">
  <label>Username: <input type="text" name="username"></label><br>
  <label>Password: <input type="password" name="password"></label><br>
  <label><input type="checkbox" name="remember" value="1"> Keep me logged in</label><br>
  <input type="submit" value="Login">
</form>
'''

HOME_TEMPLATE = '''
<!doctype html>
<title>Home</title>
<h1>Home</h1>
{% if user %}
  <p>Logged in as {{ user }}</p>
  <p><a href="{{ url_for('logout') }}">Logout</a></p>
{% else %}
  <p>You are not logged in.</p>
  <p><a href="{{ url_for('login') }}">Login</a></p>
{% endif %}
'''

@app.route('/')
def home():
    user = session.get('user')
    return render_template_string(HOME_TEMPLATE, user=user)

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username', '')
        password = request.form.get('password', '')
        remember = request.form.get('remember')

        if USERS.get(username) == password:
            session['user'] = username
            session.permanent = bool(remember)
            flash('Logged in successfully.')
            return redirect(url_for('home'))

        flash('Invalid username or password.')
    return render_template_string(LOGIN_TEMPLATE)

@app.route('/logout')
def logout():
    session.pop('user', None)
    session.permanent = False
    flash('Logged out successfully.')
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)